import React from 'react';
import { ShieldAlert, Activity, Ban, Globe } from 'lucide-react';

const StatCards = () => {
  const stats = [
    { title: "Total Attacks", value: "1,432", icon: <ShieldAlert color="#ef4444" />, color: "#ef4444" },
    { title: "Active Threats", value: "8", icon: <Activity color="#eab308" />, color: "#eab308" },
    { title: "Blocked IPs", value: "245", icon: <Ban color="#00ff9d" />, color: "#00ff9d" },
    { title: "Affected Regions", value: "12", icon: <Globe color="#3b82f6" />, color: "#3b82f6" }
  ];

  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '20px' }}>
      {stats.map((stat, index) => (
        <div key={index} style={{ background: '#1a1f2e', padding: '20px', borderRadius: '12px', display: 'flex', alignItems: 'center', gap: '15px', borderLeft: `4px solid ${stat.color}` }}>
          <div style={{ background: '#0b0f19', padding: '10px', borderRadius: '8px' }}>{stat.icon}</div>
          <div>
            <h4 style={{ margin: 0, color: '#94a3b8', fontSize: '14px' }}>{stat.title}</h4>
            <h2 style={{ margin: 0, color: 'white', fontSize: '24px' }}>{stat.value}</h2>
          </div>
        </div>
      ))}
    </div>
  );
};

export default StatCards;
